1539 void VPInstructionWithType::execute(VPTransformState &State) {
1540   State.setDebugLocFrom(getDebugLoc());
1541   if (isScalarCast()) {
1542     Value *Op = State.get(getOperand(0), VPLane(0));
1543     Value *Cast = State.Builder.CreateCast(Instruction::CastOps(getOpcode()),
1544                                            Op, ResultTy);
1545     State.set(this, Cast, VPLane(0));
1546     return;
1547   }
1548   switch (getOpcode()) {
1549   case VPInstruction::StepVector: {
1550     Value *StepVector =
1551         State.Builder.CreateStepVector(VectorType::get(ResultTy, State.VF));
1552     State.set(this, StepVector);
1553     break;
1554   }
1555   case VPInstruction::VScale: {
1556     Value *VScale = State.Builder.CreateVScale(ResultTy);
1557     State.set(this, VScale, true);
1558     break;
1559   }
1560 
1561   default:
1562     llvm_unreachable("opcode not implemented yet");
1563   }
1564 }
