1593 void VPPhi::execute(VPTransformState &State) {
1594   State.setDebugLocFrom(getDebugLoc());
1595   PHINode *NewPhi = State.Builder.CreatePHI(
1596       State.TypeAnalysis.inferScalarType(this), 2, getName());
1597   unsigned NumIncoming = getNumIncoming();
1598   if (getParent() != getParent()->getPlan()->getScalarPreheader()) {
1599     // TODO: Fixup all incoming values of header phis once recipes defining them
1600     // are introduced.
1601     NumIncoming = 1;
1602   }
1603   for (unsigned Idx = 0; Idx != NumIncoming; ++Idx) {
1604     Value *IncV = State.get(getIncomingValue(Idx), VPLane(0));
1605     BasicBlock *PredBB = State.CFG.VPBB2IRBB.at(getIncomingBlock(Idx));
1606     NewPhi->addIncoming(IncV, PredBB);
1607   }
1608   State.set(this, NewPhi, VPLane(0));
1609 }
