1642 void VPIRInstruction::extractLastLaneOfLastPartOfFirstOperand(
1643     VPBuilder &Builder) {
1644   assert(isa<PHINode>(getInstruction()) &&
1645          "can only update exiting operands to phi nodes");
1646   assert(getNumOperands() > 0 && "must have at least one operand");
1647   VPValue *Exiting = getOperand(0);
1648   if (isa<VPIRValue>(Exiting))
1649     return;
1650 
1651   Exiting = Builder.createNaryOp(VPInstruction::ExtractLastPart, Exiting);
1652   Exiting = Builder.createNaryOp(VPInstruction::ExtractLastLane, Exiting);
1653   setOperand(0, Exiting);
1654 }
