1690 void VPPhiAccessors::removeIncomingValueFor(VPBlockBase *IncomingBlock) const {
1691   VPRecipeBase *R = const_cast<VPRecipeBase *>(getAsRecipe());
1692   assert(R->getNumOperands() == R->getParent()->getNumPredecessors() &&
1693          "Number of phi operands must match number of predecessors");
1694   unsigned Position = R->getParent()->getIndexForPredecessor(IncomingBlock);
1695   R->removeOperand(Position);
1696 }
